const items = $input.all();
const tenantId = items[0]?.json?.tenant_id || '';
const today = new Date().toISOString().split('T')[0];
const tomorrow = new Date(Date.now() + 86400000).toISOString().split('T')[0];

const todayInterviews = items.filter(i => i.json.interview_date === today || String(i.json.interview_date).startsWith(today));
const tomorrowInterviews = items.filter(i => i.json.interview_date === tomorrow || String(i.json.interview_date).startsWith(tomorrow));

function formatInterview(iv) {
  const j = iv.json;
  let html = `<div style="border:1px solid #ddd;border-radius:8px;padding:16px;margin:12px 0;background:#fafafa;">`;
  html += `<h3 style="margin:0 0 8px 0;color:#1a5276;">${j.company_name} &mdash; ${j.role_title}</h3>`;
  html += `<table style="width:100%;font-size:14px;">`;
  html += `<tr><td style="padding:4px 8px;font-weight:bold;width:140px;">Time</td><td>${j.interview_start_time || 'TBC'} - ${j.interview_end_time || 'TBC'} (${j.interview_duration_minutes || 60} min)</td></tr>`;
  html += `<tr><td style="padding:4px 8px;font-weight:bold;">Format</td><td>${(j.interview_format || '').replace(/_/g, ' ')} | ${j.interview_track}</td></tr>`;
  html += `<tr><td style="padding:4px 8px;font-weight:bold;">Stage</td><td>${(j.interview_stage || 'Not specified').replace(/_/g, ' ')}</td></tr>`;

  if (j.location_type === 'remote' || j.video_platform) {
    html += `<tr><td style="padding:4px 8px;font-weight:bold;">Platform</td><td>${j.video_platform || 'Video'} ${j.video_link ? '&mdash; <a href="' + j.video_link + '">Join Link</a>' : ''}</td></tr>`;
  }
  if (j.physical_address) {
    html += `<tr><td style="padding:4px 8px;font-weight:bold;">Location</td><td>${j.physical_address}</td></tr>`;
  }
  if (j.interviewer_names && j.interviewer_names.length > 0) {
    html += `<tr><td style="padding:4px 8px;font-weight:bold;">Interviewers</td><td>${j.interviewer_names.join(', ')}</td></tr>`;
  }
  if (j.travel_mode) {
    html += `<tr><td style="padding:4px 8px;font-weight:bold;">Travel</td><td>${j.travel_mode} &mdash; depart ${j.departure_time || 'TBC'} (${j.travel_minutes} min, ~GBP ${j.travel_cost || 'N/A'})</td></tr>`;
  }
  if (j.what_to_prepare) {
    html += `<tr><td style="padding:4px 8px;font-weight:bold;">Prepare</td><td>${j.what_to_prepare}</td></tr>`;
  }
  if (j.dress_code) {
    html += `<tr><td style="padding:4px 8px;font-weight:bold;">Dress Code</td><td>${j.dress_code}</td></tr>`;
  }

  html += `<tr><td style="padding:4px 8px;font-weight:bold;">Prep Brief</td><td>${j.has_prep_brief ? '&#9989; Ready' : '&#9888;&#65039; Not yet generated'}</td></tr>`;
  html += `<tr><td style="padding:4px 8px;font-weight:bold;">Status</td><td>${j.status}</td></tr>`;
  html += `</table></div>`;
  return html;
}

let emailHtml = `<div style="font-family:Arial,sans-serif;max-width:650px;">`;

// Today section
if (todayInterviews.length > 0) {
  emailHtml += `<h2 style="color:#1a5276;border-bottom:2px solid #1a5276;padding-bottom:8px;">Today's Interviews (${todayInterviews.length})</h2>`;
  todayInterviews.forEach(iv => { emailHtml += formatInterview(iv); });
} else {
  emailHtml += `<h2 style="color:#1a5276;">No interviews today</h2>`;
}

// Tomorrow section
if (tomorrowInterviews.length > 0) {
  emailHtml += `<h2 style="color:#2e86c1;border-bottom:2px solid #2e86c1;padding-bottom:8px;margin-top:24px;">Tomorrow's Interviews (${tomorrowInterviews.length})</h2>`;
  tomorrowInterviews.forEach(iv => { emailHtml += formatInterview(iv); });
}

// Quick reminders
emailHtml += `<div style="margin-top:24px;padding:16px;background:#eaf2f8;border-radius:8px;">`;
emailHtml += `<h3 style="margin:0 0 8px 0;">Quick Reminders</h3>`;
emailHtml += `<ul style="margin:0;padding-left:20px;">`;
emailHtml += `<li>Test video/audio 15 minutes before remote interviews</li>`;
emailHtml += `<li>Have a glass of water and your notes ready</li>`;
emailHtml += `<li>Review your prep brief one final time</li>`;
emailHtml += `<li>Prepare 2-3 questions to ask at the end</li>`;
emailHtml += `</ul></div>`;

emailHtml += `<hr style="margin-top:24px;"><p style="font-size:12px;color:#888;">Selvi Job App &mdash; Module 6: Interview Scheduling &amp; Preparation</p></div>`;

const totalToday = todayInterviews.length;
const totalTomorrow = tomorrowInterviews.length;
let subject = '';
if (totalToday > 0 && totalTomorrow > 0) {
  subject = `Today: ${totalToday} interview${totalToday > 1 ? 's' : ''} | Tomorrow: ${totalTomorrow} interview${totalTomorrow > 1 ? 's' : ''}`;
} else if (totalToday > 0) {
  subject = `Today's Interviews: ${totalToday} scheduled`;
} else {
  subject = `Tomorrow's Interviews: ${totalTomorrow} scheduled`;
}

return {
  subject: subject,
  emailHtml: emailHtml,
  totalToday: totalToday,
  totalTomorrow: totalTomorrow
};

